lemma InSeqExtend(x: int, s: seq<int>, y: int)
  requires InSeq(x, s)
  ensures InSeq(x, s + [y])
{
  var w :| 0 <= w < |s| && s[w] == x;
  assert (s + [y])[w] == x;
}

